file.content:
locals {
  rabbit_queue_scaling_enabled = var.keda_scaling_enabled && var.keda_scaling_type == "rabbit"
}

resource "kubernetes_manifest" "triggerauthentication_rabbitmq" {
  count = local.rabbit_queue_scaling_enabled ? 1 : 0
  manifest = {
    "apiVersion" = "keda.sh/v1alpha1"
    "kind"       = "TriggerAuthentication"
    "metadata"   = {
      "name"      = "${local.service-suffix}-keda-trigger-auth-rabbitmq-conn"
      "namespace" = var.namespace
    }
    "spec" = {
      "secretTargetRef" = [
        {
          "key"       = "AMQP_HOST"
          "name"      = "${local.service-suffix}-rabbit-secret"
          "parameter" = "host"
        },
      ]
    }
  }
}

resource "kubernetes_manifest" "scaledobject_rabbitmq" {
  count = local.rabbit_queue_scaling_enabled ? 1 : 0
  manifest = {
    "apiVersion" = "keda.sh/v1alpha1"
    "kind"       = "ScaledObject"
    "metadata"   = {
      "name"      = "${local.service-suffix}-rabbitmq"
      "namespace" = var.namespace
    }
    "spec" = {
      "scaleTargetRef" = {
        "name" = local.service-suffix
      }
      "advanced"={
        "horizontalPodAutoscalerConfig"={
          "behavior"={
            "scaleDown"={
              "stabilizationWindowSeconds" = var.stabilizationWindowSeconds
            }
          }
        }
      }
      "cooldownPeriod" = var.cooldown_period
      "maxReplicaCount" = var.max_replicas
      "minReplicaCount" = var.min_replicas
      "triggers"       = [
        {
          "authenticationRef" = {
            "name" = kubernetes_manifest.triggerauthentication_rabbitmq[0].manifest.metadata.name
          }
          "metadata" = {
            "mode"      = "QueueLength"
            "protocol"  = "amqp"
            "queueName" = var.input_queue
            "value"     = var.queue_threshold
          }
          "type" = "rabbitmq"
        },
      ]
    }
  }
}
